#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int cmp_double(const void *a, const void *b) {
    double da = *(const double *)a;
    double db = *(const double *)b;
    if (da < db) return -1;
    if (da > db) return 1;
    return 0;
}

int feasible(double *pos, int n, double T, double D) {
    double cur = fmax(0.0, pos[0] - D);
    if (cur > pos[0] + D) return 0;
    for (int i = 1; i < n; ++i) {
        double earliest = cur + T;
        double left = pos[i] - D;
        double right = pos[i] + D;
        if (earliest > right) return 0;
        cur = fmax(earliest, left);
    }
    return 1;
}

int main() {
    int K;
    if (scanf("%d", &K) != 1) return 0;
    const double INF = 1e10;
    const double EPS = 5e-5; // 0.00005
    while (K--) {
        int N;
        double T;
        scanf("%d %lf", &N, &T);
        double *a = (double *)malloc(N * sizeof(double));
        for (int i = 0; i < N; ++i) scanf("%lf", &a[i]);
        qsort(a, N, sizeof(double), cmp_double);
        double low = 0.0, high = INF, ans = 0.0;
        while (high - low > EPS) {
            double mid = (low + high) / 2.0;
            if (feasible(a, N, T, mid)) {
                ans = mid;
                high = mid;
            } else {
                low = mid;
            }
        }
        printf("%.4f\n", ans);
        free(a);
    }
    return 0;
}

