bool feasible(const vector<double>& pos, double T, double D) {
    double cur = max(0.0, pos[0] - D);
    if (cur > pos[0] + D) return false;
    for (size_t i = 1; i < pos.size(); ++i) {
        double earliest = cur + T;
        double left = pos[i] - D;
        double right = pos[i] + D;
        if (earliest > right) return false;
        cur = max(earliest, left);
    }
    return true;
}

