import java.io.*;
import java.util.*;

public class Main {
    private static boolean feasible(double[] pos, double T, double D) {
        double cur = Math.max(0.0, pos[0] - D);
        if (cur > pos[0] + D) return false;
        for (int i = 1; i < pos.length; i++) {
            double earliest = cur + T;
            double left = pos[i] - D;
            double right = pos[i] + D;
            if (earliest > right) return false;
            cur = Math.max(earliest, left);
        }
        return true;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int K = Integer.parseInt(br.readLine().trim());
        final double INF = 1e10;
        final double EPS = 5e-5;
        StringBuilder out = new StringBuilder();
        while (K-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            double T = Double.parseDouble(st.nextToken());
            double[] a = new double[N];
            for (int i = 0; i < N; i++) {
                a[i] = Double.parseDouble(br.readLine().trim());
            }
            Arrays.sort(a);
            double low = 0.0, high = INF, ans = 0.0;
            while (high - low > EPS) {
                double mid = (low + high) / 2.0;
                if (feasible(a, T, mid)) {
                    ans = mid; high = mid;
                } else low = mid;
            }
            out.append(String.format(Locale.US, "%.4f\n", ans));
        }
        System.out.print(out.toString());
    }
}

